query:
MATCH (u:User)-[r:RATED]->()
WITH u, count(r) AS num_ratings
RETURN round(avg(num_ratings), 2) AS avg_ratings_per_user;

MATCH (m:Movie)-[h:HAS_GENRE]->(g:Genre)
RETURN g AS genre, count(DISTINCT m) AS movie_count
ORDER BY movie_count DESC;

MATCH (u:User {userId: 606})-[r:RATED]->(m:Movie)-[hg:HAS_GENRE]->(g:Genre)
WHERE r.rating >= 4.8
RETURN u, r, m, hg, g;
